(window.courseContentFiles = window.courseContentFiles || {})["000003/0011"] = "<!DOCTYPE html>\n<html lang=\"bg\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>document</title>\n  <link rel=\"stylesheet\" href=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.css\">\n  <style>\n    body {\n      font-family: \"Open Sans\", Arial, sans-serif;\n      max-width: 1550px;\n      margin: 0.5rem auto;\n      padding: 0 1rem;\n      line-height: 1.6;\n      color: #1f2937;\n    }\n    h1, h2, h3, h4 {\n      font-weight: 600;\n      margin-top: 0.7em;\n      margin-bottom: 0;\n      color: #588157;\n      line-height: 1.3;\n    }\n    h1 { font-size: 1.65em; }\n    h2 { font-size: 1.3em; }\n    h3 { font-size: 1.1em; margin-bottom: 0; }\n    h4 { font-size: 1.05em; margin-bottom: 0; }\n    h1 + h2, h1 + h3, h1 + h4, h2 + h3, h2 + h4, h3 + h4 { margin-top: 0; }\n    p {\n      margin: 0.3em 0;\n      white-space: pre-wrap;\n    }\n    p + p {\n      margin-top: 0.55em;\n    }\n    hr {\n      margin: 0.45em 0 0.2em;\n    }\n    hr + h1,\n    hr + h2,\n    hr + h3,\n    hr + h4 {\n      margin-top: 0.2em;\n    }\n    hr + p,\n    hr + ul,\n    hr + ol,\n    hr + blockquote,\n    hr + pre,\n    hr + table {\n      margin-top: 0.08em;\n    }\n    p + ul, p + ol { margin-top: 0.2em; }\n    h1 + p, h2 + p, h3 + p, h4 + p,\n    h1 + ul, h2 + ul, h3 + ul, h4 + ul,\n    h1 + ol, h2 + ol, h3 + ol, h4 + ol {\n      margin-top: 0;\n    }\n    h1 + table, h2 + table, h3 + table, h4 + table {\n      margin-top: -0.2em;\n    }\n    ul, ol {\n      margin: 0.2em 0;\n      padding-left: 1.5em;\n      list-style-position: outside;\n    }\n    li { margin: 0.2em 0; }\n    li p {\n      margin: 0;\n      padding: 0;\n      display: inline;\n    }\n    li > ul, li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    ul ul, ul ol, ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    ul ul { list-style-type: circle; }\n    ul ul ul { list-style-type: square; }\n    strong { font-weight: 600; }\n    em { font-style: italic; }\n    code {\n      background: rgba(218, 215, 205, 0.3);\n      padding: 2px 6px;\n      border-radius: 3px;\n      font-family: \"Courier New\", monospace;\n      font-size: 0.9em;\n    }\n    pre {\n      background: rgba(255, 255, 255, 0.5);\n      padding: 12px;\n      border-radius: 4px;\n      overflow-x: auto;\n      margin: 0.5em 0;\n      font-family: \"Courier New\", monospace;\n    }\n    pre code {\n      background: none;\n      padding: 0;\n    }\n    blockquote {\n      border-left: 3px solid #588157;\n      padding-left: 1em;\n      margin: 0.5em 0;\n      font-style: italic;\n      color: #166534;\n    }\n    table {\n      border-collapse: collapse;\n      margin: 0.75em 0;\n      width: 100%;\n      table-layout: auto;\n    }\n    th, td {\n      border: 1px solid rgba(2, 2, 2, 0.2);\n      padding: 6px 10px;\n      text-align: left;\n      vertical-align: top;\n      height: 24px;\n      line-height: 1.2;\n    }\n    thead th {\n      background: rgba(88, 129, 87, 0.13);\n      font-weight: 600;\n    }\n    tbody tr:nth-child(odd) {\n      background: rgba(88, 129, 87, 0.06);\n    }\n    /* Image alignment rules for exported content and md-viewer */\n    img[data-align=\"left\"] {\n      display: block;\n      margin: 8px auto 8px 0;\n    }\n    img[data-align=\"center\"] {\n      display: block;\n      margin: 8px auto;\n    }\n    img[data-align=\"right\"] {\n      display: block;\n      margin: 8px 0 8px auto;\n    }\n    .audio-link-inline {\n      display: inline-flex;\n      align-items: center;\n      gap: 7px;\n      margin: 0.2em 0;\n      max-width: 100%;\n      vertical-align: middle;\n      padding: 5px 7px;\n      border: 1px solid #d8e5d4;\n      border-radius: 9px;\n      background: #f4f9f2;\n    }\n    .audio-link-icon {\n      width: 26px;\n      height: 26px;\n      border: 1px solid #588157;\n      border-radius: 8px !important;\n      background: transparent;\n      color: #2f5d50;\n      cursor: pointer;\n      line-height: 1;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      flex: 0 0 26px;\n      padding: 0;\n      text-align: center;\n      font-size: 12px;\n      font-weight: 700;\n    }\n    .audio-link-icon img,\n    .audio-time {\n      display: none !important;\n    }\n    .audio-link-label {\n      max-width: 125px;\n      min-width: 0;\n      font-size: 0.82em;\n      font-weight: 700;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .audio-link-label:empty {\n      display: none;\n    }\n    .audio-progress {\n      width: 118px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-volume {\n      width: 44px;\n      accent-color: #588157;\n      cursor: pointer;\n    }\n    .audio-progress,\n    .audio-volume {\n      height: 4px;\n      appearance: none;\n      -webkit-appearance: none;\n      background: transparent;\n    }\n    .audio-link-inline audio {\n      display: none;\n    }\n    a {\n      color: inherit; /* Changed to inherit */\n      text-decoration: underline;\n    }\n    a:hover {\n      color: #74b673;\n    }\n    /* Keep <p> tags inside list items on same line (as they appear in editor) */\n    li p {\n      margin: 0 !important;\n      padding: 0 !important;\n      display: inline !important;\n    }\n    /* Prevent nested list paragraph issues */\n    li > ul,\n    li > ol {\n      margin: 0.15em 0 0 0;\n      padding-left: 1.5em;\n    }\n    /* Ensure list structure is clean */\n    ul ul, ul ol,\n    ol ul, ol ol {\n      margin-top: 0.1em;\n      padding-left: 1.5em;\n    }\n    @media (max-width: 900px) {\n      body {\n        margin: 0.5rem 0;\n        padding: 0 0.5rem;\n        font-size: 16px;\n      }\n      h1 { font-size: 1.65em; }\n      h2 { font-size: 1.3em; }\n      h3 { font-size: 1.1em; }\n      p { margin: 0.3em 0; }\n      p + p { margin-top: 0.55em; }\n      ul, ol { padding-left: 1.5em; }\n      li { margin: 0.2em 0; }\n      table { font-size: 0.9em; }\n      th, td { padding: 6px 10px; }\n    }\n    .editor-note {\n      text-decoration: underline dotted #a3b18a;\n      text-decoration-thickness: 2px;\n      text-underline-offset: 2px;\n      text-decoration-skip-ink: none;\n      cursor: help;\n      position: relative;\n    }\n    .note-tooltip {\n      display: none;\n      position: absolute;\n      background-color: #f0f7f0;\n      color: #1f2937;\n      border: 1px solid #588157;\n      border-radius: 4px;\n      padding: 8px 12px;\n      width: fit-content;\n      max-width: min(700px, calc(100vw - 20px));\n      max-height: calc(100vh - 20px);\n      overflow: auto;\n      box-sizing: border-box;\n      box-shadow: 0 2px 8px rgba(0,0,0,0.2);\n      z-index: 10000;\n      font-size: 0.9em;\n      line-height: 1.4;\n      word-wrap: break-word;\n    }\n    .note-tooltip ul, .note-tooltip ol {\n      margin: 0 !important;\n      padding-left: 20px !important;\n    }\n    .note-tooltip li {\n      margin: 0 0 0.1em 0 !important;\n      padding: 0 !important;\n      line-height: 1.2 !important;\n    }\n    .note-tooltip li:last-child {\n      margin-bottom: 0 !important;\n    }\n    .note-tooltip .note-table-scroll {\n      overflow-x: hidden;\n      margin: 0.3em 0;\n      max-width: 100%;\n    }\n    .note-tooltip table {\n      border-collapse: collapse;\n      width: 100%;\n      max-width: 100%;\n      min-width: 0;\n      table-layout: fixed;\n      background: #ffffff;\n    }\n    .note-tooltip th,\n    .note-tooltip td {\n      border: 1px solid rgba(88, 129, 87, 0.35);\n      padding: 4px 8px;\n      text-align: left;\n      vertical-align: top;\n      line-height: 1.3;\n      white-space: normal;\n      overflow-wrap: anywhere;\n      word-break: break-word;\n    }\n    .note-tooltip thead th {\n      background: rgba(88, 129, 87, 0.12);\n      font-weight: 600;\n    }\n  </style>\n  <script>\n    document.addEventListener('DOMContentLoaded', function() {\n      const tooltip = document.createElement('div');\n      tooltip.className = 'note-tooltip';\n      document.body.appendChild(tooltip);\n\n      function parseNoteMarkdown(text) {\n        if (!text) return '';\n\n        const splitTableCells = function(line) {\n          return String(line || '')\n            .trim()\n            .replace(/^\\|/, '')\n            .replace(/\\|$/, '')\n            .split('|')\n            .map(function(cell) { return cell.trim(); });\n        };\n\n        const isTableSeparatorLine = function(line) {\n          const cells = splitTableCells(line);\n          return cells.length > 0 && cells.every(function(cell) {\n            return /^:?-{3,}:?$/.test(cell);\n          });\n        };\n\n        const getTableAlignment = function(cell) {\n          if (/^:-{3,}:$/.test(cell)) return 'center';\n          if (/^-{3,}:$/.test(cell)) return 'right';\n          if (/^:-{3,}$/.test(cell)) return 'left';\n          return '';\n        };\n\n        let lines = text.split('\\n');\n        let html = [];\n        let stack = [];\n\n        for (let i = 0; i < lines.length; i++) {\n          let line = lines[i];\n\n          let indentMatch = line.match(/^(\\s*)/);\n          let indent = indentMatch ? indentMatch[1].length : 0;\n          let content = line.trim();\n\n          const nextLine = i + 1 < lines.length ? lines[i + 1].trim() : '';\n          const maybeTableHeader = content.includes('|') && splitTableCells(content).length >= 2;\n          const maybeTableSeparator = nextLine.includes('|') && isTableSeparatorLine(nextLine);\n\n          if (maybeTableHeader && maybeTableSeparator) {\n            while (stack.length > 0) {\n              let closed = stack.pop();\n              html.push('</' + closed.type + '>');\n            }\n\n            const headerCells = splitTableCells(content);\n            const alignCells = splitTableCells(nextLine);\n\n            html.push('<div class=\"note-table-scroll\"><table><thead><tr>');\n            headerCells.forEach(function(cell, idx) {\n              const align = getTableAlignment(alignCells[idx] || '');\n              const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n              html.push('<th' + alignAttr + '>' + cell + '</th>');\n            });\n            html.push('</tr></thead><tbody>');\n\n            i += 2;\n            while (i < lines.length) {\n              const rowLine = lines[i].trim();\n              if (!rowLine || !rowLine.includes('|')) break;\n              if (isTableSeparatorLine(rowLine)) {\n                i++;\n                continue;\n              }\n\n              const rowCells = splitTableCells(rowLine);\n              if (rowCells.length === 0) {\n                i++;\n                continue;\n              }\n\n              html.push('<tr>');\n              rowCells.forEach(function(cell, idx) {\n                const align = getTableAlignment(alignCells[idx] || '');\n                const alignAttr = align ? ' style=\"text-align:' + align + ';\"' : '';\n                html.push('<td' + alignAttr + '>' + cell + '</td>');\n              });\n              html.push('</tr>');\n              i++;\n            }\n\n            html.push('</tbody></table></div>');\n            i--;\n            continue;\n          }\n\n          let isUl = /^[-*]\\s+(.+)/.test(content);\n          let isOl = /^\\d+\\.\\s+(.+)/.test(content);\n\n          if (isUl || isOl) {\n            let listType = isUl ? 'ul' : 'ol';\n            let match = isUl ? content.match(/^[-*]\\s+(.+)/) : content.match(/^\\d+\\.\\s+(.+)/);\n            let itemText = match[1];\n\n            if (stack.length === 0) {\n              stack.push({ type: listType, indent: indent });\n              html.push('<' + listType + '>');\n            } else {\n              let last = stack[stack.length - 1];\n\n              if (indent > last.indent) {\n                stack.push({ type: listType, indent: indent });\n                html.push('<' + listType + '>');\n              } else if (indent < last.indent) {\n                while (stack.length > 0 && stack[stack.length - 1].indent > indent) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                }\n                if (stack.length === 0 || stack[stack.length - 1].indent !== indent) {\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                } else if (stack[stack.length - 1].type !== listType) {\n                   let closed = stack.pop();\n                   html.push('</' + closed.type + '>');\n                   stack.push({ type: listType, indent: indent });\n                   html.push('<' + listType + '>');\n                }\n              } else {\n                if (last.type !== listType) {\n                  let closed = stack.pop();\n                  html.push('</' + closed.type + '>');\n                  stack.push({ type: listType, indent: indent });\n                  html.push('<' + listType + '>');\n                }\n              }\n            }\n            html.push('<li>' + itemText + '</li>');\n          } else {\n            if (content !== '') {\n               while (stack.length > 0) {\n                 let closed = stack.pop();\n                 html.push('</' + closed.type + '>');\n               }\n            }\n            if (/^(?:---|\\*\\*\\*|___)$/.test(content)) {\n              html.push('<hr>');\n            } else if (/^#{1,4}\\s+/.test(content)) {\n              const headingMatch = content.match(/^(#{1,4})\\s+(.+)$/);\n              if (headingMatch) {\n                const level = headingMatch[1].length;\n                html.push('<h' + level + '>' + headingMatch[2] + '</h' + level + '>');\n              }\n            } else if (content) {\n              html.push(content + '<br>');\n            } else {\n              html.push('<br>');\n            }\n          }\n        }\n\n        while (stack.length > 0) {\n          let closed = stack.pop();\n          html.push('</' + closed.type + '>');\n        }\n\n        let result = html.join('')\n          .replace(/!\\[(.*?)\\]\\((.*?)\\)/g, '<img src=\"$2\" alt=\"$1\">')\n          .replace(/\\*\\*(.+?)\\*\\*/g, '<strong>$1</strong>')\n          .replace(/__(.+?)__/g, '<strong>$1</strong>')\n          .replace(/\\*(.+?)\\*/g, '<em>$1</em>')\n          .replace(/_(.+?)_/g, '<em>$1</em>')\n          .replace(/`(.+?)`/g, '<code>$1</code>')\n          .replace(/\\[(.+?)\\]\\((.+?)\\)/g, '<a href=\"$2\" target=\"_blank\">$1</a>');\n\n        result = result\n          .replace(/<br><ul>/g, '<ul>')\n          .replace(/<br><ol>/g, '<ol>')\n          .replace(/</ul><br>/g, '</ul>')\n          .replace(/</ol><br>/g, '</ol>');\n\n        return result;\n      }\n\n      document.body.addEventListener('mouseover', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          const note = e.target.dataset.note;\n          if (note) {\n            tooltip.innerHTML = parseNoteMarkdown(note);\n            tooltip.style.display = 'block';\n            const rect = e.target.getBoundingClientRect();\n            const tooltipRect = tooltip.getBoundingClientRect();\n            const pageX = window.scrollX || window.pageXOffset;\n            const pageY = window.scrollY || window.pageYOffset;\n            const maxLeft = pageX + window.innerWidth - tooltipRect.width - 10;\n            const minLeft = pageX + 10;\n\n            let left = rect.left + pageX;\n            if (left > maxLeft) left = maxLeft;\n            if (left < minLeft) left = minLeft;\n\n            let top = rect.bottom + pageY + 6;\n            const maxTop = pageY + window.innerHeight - tooltipRect.height - 10;\n            if (top > maxTop) {\n              top = rect.top + pageY - tooltipRect.height - 6;\n            }\n            if (top < pageY + 10) top = pageY + 10;\n\n            tooltip.style.left = left + 'px';\n            tooltip.style.top = top + 'px';\n          }\n        }\n      });\n\n      document.body.addEventListener('mouseout', function(e) {\n        if (e.target.classList.contains('editor-note')) {\n          setTimeout(() => {\n            if (!tooltip.matches(':hover')) {\n              tooltip.style.display = 'none';\n            }\n          }, 100);\n        }\n      });\n\n      tooltip.addEventListener('mouseleave', function() {\n        tooltip.style.display = 'none';\n      });\n    });\n  </script>\n</head>\n<body>\n<h1 style=\"text-align: center\">Тема 89. Хиперплазия на простатната жлеза. Морфологична характеристика, усложнения.</h1><p><span class=\"editor-note\" data-note=\"# Анатомия на простатната жлеза\nПри млади мъже на възраст **25–30 години** простатната жлеза тежи около **20 g**.\nСлед **50-годишна възраст** тя постепенно започва да атрофира, а към **80-те години** ацините ѝ облитерират.\n## Зонална анатомия\nТопографски в детската простата се различават пет дяла:\n* преден;\n* срединен — централен;\n* ляв страничен;\n* десен страничен;\n* заден.\nПри възрастния мъж последните три дяла — **ляв страничен**, **десен страничен** и **заден** — се разглеждат като единна група, наречена **периферна зона**.\n## Периферна зона\n**Периферната зона** заема около **75%** от масата на простатата.\nТя съдържа дълги, разклоняващи се канали, тапицирани с **цилиндричен епител**.\nВ тази зона, особено в **задния дял**, най-често се развиват **аденокарциноми** на простатната жлеза.\n## Срединна зона\n**Срединната зона**, или **централният лоб**, е съставена от къси жлези, тапицирани с **цилиндричен епител**.\nВ близост до уретрата епителът преминава в **преходен епител**.\nТази зона заема около **23%** от масата на простатната жлеза и се намира под контрола на **тестикуларните андрогени**.\nВ нея най-често се развива **нодуларна жлезиста хиперплазия** при възрастни мъже.\n## Предна зона\n**Предната зона** е изградена главно от **фибро-гладкомускулна строма**, съдържаща:\n* колагенни влакна;\n* еластични влакна;\n* малък брой жлези.\nВ лумена на жлезите се откриват **corpora amylacea**.\nТе нормално се появяват около **10-годишна възраст**, нарастват прогресивно до **40–50 години**, след което количеството им намалява.\nВ патогенетично отношение **corpora amylacea** се свързват с дегенерация и десквамация на епителните клетки на жлезите.\" id=\"note-1778940443079-1\"><span style=\"color: rgb(236, 105, 36)\"><strong>Анатомия.</strong></span></span></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><p><strong>Хиперплазията на простатната жлеза</strong> — <strong>hyperplasia glandulae prostatae</strong> — представлява изразено разрастване на жлезистия и/или стромалния компонент на простатата.</p><h2>Морфогенеза</h2><p>Същността на заболяването се свежда до хиперплазия на няколко нива:</p><ul><li>на нивото на <strong>жлезите</strong>;</li><li>на нивото на простатната <strong>строма</strong> — гладкомускулна и фиброваскуларна;</li><li>едновременно на двата компонента.</li></ul><h2>Морфологични форми</h2><p>В зависимост от преобладаващия компонент хиперплазията се разделя на:</p><ul><li><strong>аденоматозна</strong>;</li><li><strong>фиброматозна / лейомиоматозна</strong>;</li><li><strong>смесена</strong> — адено-фибро-лейомиоматозна.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Аденоматозна хиперплазия</h2><p><strong>Макроскопски:</strong> характеризира се с увеличаване на броя и размерите на жлезите. Част от тях са дилатирани и имат кистичен вид. Хиперплазията се очертава като възел със сивкав оттенък, а на срез хиперплазиралите възли изглеждат „<strong>шуплести</strong>“.</p><p><strong>Микроскопски:</strong> жлезите са тапицирани с едноредов цилиндричен епител, който на места образува нежни папили, вдаващи се към лумена. Кистозните формации обикновено са тапицирани с <strong>кубичен епител</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Фиброматозна / лейомиоматозна хиперплазия</h2><p><strong>Микроскопски:</strong> характеризира се със снопчест строеж на пролифериралата стромална тъкан. Разрасналата строма притиска и деформира жлезите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Смесена хиперплазия</h2><p><strong>Макроскопски:</strong> по-често се наблюдава при случаи с ясно изразена <strong>нодуларна структура</strong>. Тя се дължи на склонността на хиперплазиралата строма да се разполага циркулярно около жлезите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Нодуларна хиперплазия</h2><p><strong>Нодуларната хиперплазия</strong> е типичен пример за <strong>корелативна / хормонална хипертрофия</strong>. </p><p>Среща се най-често след <strong>55-годишна възраст</strong>, а в осмото десетилетие почти <strong>3/4 от мъжете</strong> са засегнати. Преди <strong>40-годишна възраст</strong> хиперплазията на простатата е рядка.</p><h3>Клинично значение</h3><p>Клиничното значение на нодуларната хиперплазия е свързано главно с последователни усложнения, започващи от затрудненото изтичане и задържането на урина.</p><p>Задържането на урина в пикочния мехур води до <strong>работна хипертрофия</strong> на стената му, последвана от <strong>дилатация</strong>. По-късно се развиват дилатация на уретерите — <strong>hydroureter</strong>, и дилатация на бъбречните легенчета — <strong>hydronephrosis</strong>.</p><p><strong>Уростазата</strong> създава условия за образуване на камъни — <strong>urolithiasis</strong> и <strong>nephrolithiasis</strong>. Попадането на микроорганизми в урината води до възпалителен процес — <strong>cystopyelonephritis</strong>.</p><p>Тези усложнения могат да затворят нов патологичен кръг с развитие на <strong>симптоматична хипертония</strong> или <strong>уросепсис</strong>.</p><h3>Макроскопски промени</h3><p>Простатната жлеза е увеличена няколкократно. Увеличената жлеза притиска <strong>уретрата</strong> и затруднява изтичането на урината.</p><p>Когато промените са локализирани предимно в средния лоб, нодуларната хиперплазия се означава със старото наименование <strong>периуретрален аденом</strong>.</p><h3>Микроскопски промени</h3><p>При изследване на ядрената <strong>ДНК плоидия</strong> пролифериралите клетки са предимно <strong>диплоидни — 2C</strong>. Само в отделни случаи се открива малка група клетки с <strong>анеуплоидно ДНК разпределение</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 90. Тумори на простатната жлеза. Клинико-морфологични форми.</h1><p><strong>Злокачествените епителни тумори</strong> са най-разпространените тумори на <strong>простатната жлеза</strong>. Срещат се предимно при възрастни мъже — <strong>60–80 години</strong>, като честотата им трайно нараства. </p><h2>Класификация</h2><p>Хистопатологичните форми на простатния карцином по <strong>СЗО</strong> са:</p><ul><li><strong>аденокарцином</strong> — ацинарен карцином;</li><li>карцином с вретеновидноклетъчна диференциация / карциносарком;</li><li>дуктален аденокарцином;</li><li>уротелен — преходноклетъчен карцином;</li><li>плоскоклетъчен карцином.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Аденокарцином — ацинарен карцином</h2><p><strong>Аденокарциномът</strong> е преобладаващият епителен тумор на простатната жлеза и съставлява около <strong>98%</strong> от тях.</p><p>Нарежда се на <strong>шесто място</strong> по честота в света и на <strong>трето място</strong> по значение при мъжете. Съставлява <strong>9,7%</strong> от карциномите при мъжете, а в развитите страни достига <strong>15,3%</strong>.</p><h3>Морфогенеза</h3><p>Мъжките полови хормони имат съществена роля в развитието и растежа на <strong>простатния карцином</strong>. В простатната жлеза <strong>тестостеронът</strong> се конвертира чрез ензима <strong>стероид-5α-редуктаза тип II</strong> до <strong>дихидротестостерон — DHT</strong>, който е метаболитно активната форма.</p><p><strong>DHT</strong> се свързва с андрогенния рецептор, след което образуваният комплекс се транслоцира до ядрото, свързва се с <strong>ДНК</strong> и активира гени с андрогенно-отговорни елементи, включително гени, контролиращи клетъчното делене.</p><p>Значението на половите хормони се подкрепя от клиничното наблюдение, че <strong>ранната предпубертетна кастрация</strong> предпазва от развитие на <strong>нодуларна хиперплазия</strong> и <strong>аденокарцином</strong>. Нерядко аденокарциномът се развива на фона на предшестваща <strong>простатна интраепителна неоплазия — ПИН</strong>.</p><h3>Клинична картина</h3><p>Субективните оплаквания са свързани предимно с нарушения в уринирането — <strong>микционни смущения</strong>. При ректално туширане се установява уголемена и уплътнена простатна жлеза, а ехографски измененията се доказват главно в <strong>задните</strong> и <strong>задностраничните части</strong> на жлезата.</p><p>При ясна клинична изява карциномът се определя като <strong>манифестен</strong>. Когато липсват клинични белези от простатата, а заболяването се проявява чрез метастази в други органи, карциномът се означава като <strong>окултен</strong>.</p><p>Най-важният лабораторен белег, който предшества клиничната симптоматика, е повишаването на <strong>простат-специфичния антиген — PSA</strong>. Той се продуцира от епителните клетки на дукталния и ацинарния епител. Стойностите му зависят от възрастта, но обикновено нива над <strong>4,5 ng/ml</strong> насочват към търсене на карцином.</p><h3>Диагноза</h3><p>Диагнозата се основава на <strong>биопсично изследване</strong> на простатната жлеза. Стандартен метод е <strong>иглената трансректална биопсия</strong>, при която минимално се вземат късчета от върха, средата и базата на двата дяла на жлезата. Материалите се поставят в отделни маркирани съдове за фиксация и обработка.</p><p>Други диагностични методи са <strong>трансуретралната резекция на простатата — ТУР</strong>, използвана обикновено при хиперплазия на жлезата, и тънкоиглената аспирационна биопсия, чието приложение днес отстъпва на иглената биопсия.</p><h3>Макроскопски промени</h3><p>Простатната жлеза е леко уголемена, но по-съществена е промяната в консистенцията. Тя става <strong>плътна</strong>, <strong>жилава</strong>, с <strong>дребнозърниста повърхност</strong> — промени, които могат да се установят при ректално туширане.</p><p>На срез туморната маса е с <strong>неясни граници</strong>, <strong>некапсулирана</strong> и прораства в околната тъкан.</p><h3>Микроскопски промени</h3><p>Туморът е изграден от жлезисти структури с различна степен на диференциация — от добре диференцирани, трудно разграничими от нормалната жлеза, до нискодиференцирани форми, съставени от лимфоцитоподобни клетки и наподобяващи хронично възпаление.</p><p>Най-важният отличителен белег е, че туморните ацини са тапицирани с <strong>един слой клетки</strong>, за разлика от нормалните ацини, които имат <strong>двуслойна епителна покривка</strong> с базални клетки.</p><p>Други характерни микроскопски белези са <strong>амфофилна цитоплазма</strong>, жлези с правилно линейно очертание, липса на нормални нагъвания и папили, хаотично разположение на ацините, различия в големината им, струпване „<strong>гръб до гръб</strong>“ и образуване на <strong>криброзни структури</strong>.</p><h3>Степенуване по Gleason</h3><p><strong>Степенуването по Gleason</strong> се основава на архитектурните промени в жлезистите структури на простатния карцином. То е предложено от <strong>Donald Gleason</strong> и не отчита степента на ядрените промени.</p><p>От <strong>1993 г.</strong> скалата на <strong>Gleason</strong> се препоръчва от <strong>СЗО</strong> за хистологично градиране на простатния карцином.</p><p>Различават се <strong>5 хистологични структурни степени</strong>:</p><ol><li><strong>Степен 1</strong> — най-високо диференцирана, с ясно оформени жлези и запазена епителна поларност.</li><li><strong>Степени 2 и 3</strong> — наблюдава се струпване и сливане на жлезите.</li><li><strong>Степен 4</strong> — жлезообразуването е частично; чести са <strong>крибриформените формации</strong> и <strong>комедонекрозите</strong>.</li><li><strong>Степен 5</strong> — доминират солидни повлекла; тубуларните и ацинарните структури почти липсват, а малки групи или единични туморни клетки инвазират стромата.</li></ol><p>Крайната оценка се представя като сбор от най-широко застъпената архитектурна картина и следващата по честота, например <strong>3 + 4 = 7</strong>. Ако във всички полета се наблюдава една и съща степен, тя се дублира — например <strong>3 + 3 = 6</strong>.</p><p>Оценката по Gleason се интерпретира така:</p><ul><li><strong>2–4</strong> — високодиференцирани карциноми;</li><li><strong>5–7</strong> — умерено диференцирани карциноми;</li><li><strong>8–10</strong> — нискодиференцирани карциноми.</li></ul><h3>Еволюция</h3><p>Простатният карцином се разпространява <strong>периневрално</strong> и метастазира предимно по лимфен път към <strong>илиачните</strong> и <strong>парааорталните лимфни възли</strong>.</p><p>Чести са и хематогенните метастази в костите. Метастазирането в <strong>тазовите кости</strong> и <strong>прешлените</strong> може да се осъществи чрез <strong>вертебралния венозен плексус на Batson</strong>.</p><h3>Прогноза</h3><p>Факторите с доказано прогностично значение са:</p><ul><li>предоперативното ниво на <strong>PSA</strong>;</li><li>степента по <strong>Gleason</strong>;</li><li>стадият по <strong>TNM</strong>;</li><li>чистотата на хирургичните резекционни ръбове.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Простатна интраепителна неоплазия — ПИН</h2><p><strong>Простатната интраепителна неоплазия — ПИН</strong> представлява неопластична трансформация на <strong>дукталния</strong> и <strong>ацинарния епител</strong>, която остава ограничена в рамките на епитела.</p><p>Различават се две степени на ПИН, като <strong>високостепенната ПИН</strong> съответства на <strong>рак in situ</strong>.</p><h3>Значение като преканцероза</h3><p><strong>ПИН</strong> се приема за <strong>преканцероза</strong>, тъй като има установена морфологична връзка между нея и <strong>аденокарцинома</strong> на простатата.</p><p>Основните доказателства са:</p><ul><li>честотата и разпространението на ПИН и аденокарцинома нарастват с възрастта;</li><li>двата процеса се локализират в едни и същи области на простатата;</li><li>при пациенти с карцином се увеличават тежестта, честотата и разпространението на ПИН;</li><li>установяват се преходи между <strong>високостепенна ПИН</strong> и <strong>карцином</strong>.</li></ul><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 91. Възпалителни заболявания на тестиса и епидидима. Хидроцеле, хематоцеле, варикоцеле.</h1><h2>Орхит / епидидимоорхит</h2><p><strong>Възпалителните заболявания на тестиса</strong> са предимно вторични или съпътстващи. Най-често се причиняват от <strong>Gram-отрицателни микроорганизми</strong>, по-рядко от вируси или гъбички.</p><p>Основният патогенетичен механизъм е <strong>ретроградното движение на урината</strong> при възпаление на пикочните пътища. В тези случаи почти винаги се въвлича и <strong>епидидимът</strong>, поради което по-точният термин е <strong>епидидимоорхит</strong>.</p><p>Според клиничното развитие и морфологичната картина се различават <strong>остри</strong> и <strong>хронични</strong> форми.</p><h3>Остър орхит / епидидимоорхит</h3><p>Острият епидидимоорхит може да бъде резултат от <strong>септицемия</strong> с бактериална инфекция или вирусно усложнение на <strong>заушка</strong> — <strong>parotitis epidemica</strong>.</p><p>Клинично се проявява с <strong>тестикуларна болка</strong> и едностранно, по-рядко двустранно, увеличение на тестиса.</p><p>Микроскопски промените са главно в <strong>интерстициума</strong>, който е оточен и първоначално инфилтриран от <strong>неутрофилни гранулоцити</strong>, а по-късно — от <strong>лимфоцити</strong>. По листовете на <strong>tunica vaginalis</strong> се открива <strong>фибринов ексудат</strong>.</p><p>В оздравителната фаза се развива <strong>дифузна фиброза</strong>, която уврежда тубулите и води до атрофия на <strong>герминативния епител</strong>, <strong>азооспермия</strong> и безплодие. Създават се условия и за <strong>венозни тромбози</strong> и <strong>тестикуларни инфаркти</strong>.</p><h3>Хроничен орхит / епидидимоорхит</h3><p>Микроскопски могат да се наблюдават <strong>специфични и неспецифични грануломатозни процеси</strong>, както и <strong>неспецифични негрануломатозни процеси</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Епидидимит</h2><p><strong>Епидидимитът</strong> е сред най-честите заболявания на епидидима и представлява възпаление на надсеменника.</p><p>Етиологията зависи от възрастта. При млади мъже най-често е свързан с <strong>гонококова инфекция</strong> и <strong>Chlamydia trachomatis</strong>, а при по-възрастни — с <strong>E. coli</strong>.</p><h2>Остър епидидимит</h2><p><strong>Острият епидидимит</strong> протича с <strong>висока температура</strong> и <strong>тестикуларна болка</strong>.</p><p>Микроскопски тъканта е <strong>хиперемирана</strong> и <strong>оточна</strong>, като в епидидима се откриват <strong>неутрофилни гранулоцити</strong>, примесени със сперма.</p><h2>Хроничен епидидимит</h2><p>Хроничните епидидимити могат да бъдат <strong>неспецифични дифузни</strong> или <strong>специфични грануломатозни</strong>.</p><p>При хроничните дифузни епидидимити броят на <strong>плазматичните клетки</strong>, <strong>лимфоцитите</strong> и <strong>хистиоцитите</strong> нараства, докато сегментоядрените левкоцити прогресивно намаляват.</p><p>Стихването на възпалителния процес се съпровожда от <strong>фиброза</strong>, която често води до <strong>облитерация</strong> или <strong>обструкция</strong> на засегнатия сегмент.</p><h2>Хроничен специфичен грануломатозен епидидимит</h2><p>Хроничните специфични грануломатозни епидидимити най-често са израз на <strong>хематогенно-дисеминирана туберкулоза</strong>.</p><p>Микроскопски се наблюдава типичен <strong>туберкул</strong>, характерен за пролиферативния стадий на туберкулозата.</p><p>Подобен гранулом, но <strong>без казеозна некроза</strong>, се развива при <strong>саркоидоза</strong>.</p><p>Хроничен грануломатозен възпалителен процес може да възникне и когато сперма излезе от канала на епидидима в интерстициума, най-често при травма. Първоначално тя предизвиква <strong>асептично възпаление</strong> с множество неутрофилни гранулоцити.</p><p>По-късно се формира <strong>сперматоцитен гранулом</strong>, изграден от лимфоцити, хистиоцити и единични гигантски многоядрени клетки тип „<strong>чуждо тяло</strong>“. Характерна е <strong>фагоцитозата на сперма</strong> от хистиоцитите.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Смесени лезии на <span class=\"editor-note\" data-note=\"## Кратка анатомия на **tunica vaginalis**\n**Tunica vaginalis** е серозна обвивка на тестиса, произхождаща от перитонеума. Тя покрива тестиса отвън и образува потенциално пространство около него.\nСъстои се от два листа:\n* **париетален лист** — разположен към скроталната стена;\n* **висцерален лист** — прилепва към повърхността на тестиса и епидидима.\nМежду двата листа има тънко пространство, в което нормално има малко количество серозна течност. При натрупване на повече течност се развива **хидроцеле**. При натрупване на кръв — **хематоцеле**, а при лимфа — **хилоцеле**.\nПод **tunica vaginalis** се намира **tunica albuginea** — плътната фиброзна капсула на тестиса. ![Image](https://files.coursebook.lol/Fenroll/2026-05-16/text-editor-images/2026/05/1778942002103-image.png &quot;width=100%&quot;)\" id=\"note-1778941986120-1\">tunica vaginalis</span></h2><p><strong>Смесените лезии на tunica vaginalis</strong> се характеризират с натрупване на различно съдържимо между двата листа на серозната обвивка или с промени в съдовете и каналите в областта на тестиса.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Furologicsurgerynwi.com%2Fwp-content%2Fuploads%2F2024%2F11%2Fhydrocele.jpg&amp;f=1&amp;nofb=1&amp;ipt=72a430bfe567ebd0e20406063f2c0847c1f2099b93cf42a27e02f054fcfb722a &quot;width=100%&quot;)\" id=\"note-1778942046775-2\">Хидроцеле</span></h3><p><strong>Хидроцеле</strong> представлява натрупване на <strong>серозна течност</strong> между двата листа на <strong>tunica vaginalis</strong>. Води до уголемяване на <strong>скроталния сак</strong> и се среща най-често във възрастта <strong>30–50 години</strong>.</p><p>Причини могат да бъдат <strong>лигиране на funiculus spermaticus</strong>, компресия на лимфните пътища от херния или неоплазми, както и <strong>хроничен епидидимит</strong>.</p><h3>Хематоцеле</h3><p><strong>Хематоцеле</strong> представлява натрупване на <strong>кръв</strong> между листовете на tunica vaginalis. Може да възникне при <strong>директна травма</strong>, <strong>торзио</strong> или <strong>хеморагична диатеза</strong>.</p><h3>Хилоцеле</h3><p><strong>Хилоцеле</strong> представлява натрупване на <strong>лимфа</strong>. Свързва се с лимфна обструкция, най-често при <strong>филариаза</strong> и <strong>елефантиаза</strong>.</p><h3>Сперматоцеле</h3><p><strong>Сперматоцеле</strong> представлява дилатация на <strong>еферентните канали</strong> или каналите на <strong>rete testis</strong>, изпълнени със семенна течност.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fhealthcare.utah.edu%2Fsites%2Fg%2Ffiles%2Fzrelqx136%2Ffiles%2Fstyles%2Ffreeform_wide%2Fpublic%2Fmedia%2Fimages%2F2021%2Fvaricocele.jpg%3Fitok%3DxIYRf_hp&amp;f=1&amp;nofb=1&amp;ipt=82c1727d451b96c643c37e6734c27d7ad14a9736fcbb77b864052544992fa4a6 &quot;width=100%&quot;)\" id=\"note-1778942085128-3\">Варикоцеле</span></h3><p><strong>Варикоцеле</strong> представлява дилатация на вените на <strong>funiculus spermaticus</strong>. Обикновено протича <strong>асимптомно</strong>.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><p><br></p><p><br></p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\" data-separator-style=\"dashed\" style=\"border-right: none; border-bottom: none; border-left: none; border-image: initial; border-top: 2px dashed rgb(88, 129, 87)\"><h1 style=\"text-align: center\">Тема 92. Доброкачествени и злокачествени тумори на тестиса и епидидима.</h1><h2>Тумори на тестисите</h2><p><strong>Тестикуларните тумори</strong> съставляват около <strong>1%</strong> от всички тумори при мъжете. Най-чести са <strong>герминативноклетъчните тумори</strong>, които представляват около <strong>90%</strong> от всички тестикуларни неоплазми.</p><p>Етиологията не е напълно изяснена. Значение имат <strong>генетичното предразположение</strong>, травми и инфекциозни причинители в част от случаите. Особено важен рисков фактор е <strong>крипторхизмът</strong>, при който рискът от малигнени герминативноклетъчни тумори при възрастни е около <strong>10–20 пъти по-висок</strong>.</p><p>Клинично туморите се проявяват с <strong>болка</strong> или <strong>уголемяване на тестиса</strong>. Понякога първата изява е от метастази в други органи — при <strong>семином</strong>, <strong>ембрионален карцином</strong> или <strong>хориокарцином</strong>. В тези случаи туморите се означават като <strong>окултни</strong>.</p><p>Някои тумори са характерни за определени възрастови групи: <strong>тератомите</strong> и <strong>туморите на ендодермалния синус</strong> се срещат главно в детска възраст до 10 години; <strong>хориокарциномите</strong> — предимно във второто и третото десетилетие; а класическият <strong>семином</strong> — най-често в четвъртото десетилетие.</p><h2>Герминативноклетъчни тумори</h2><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=http%3A%2F%2Filovepathology.com%2Fwp-content%2Fuploads%2F2020%2F05%2FSEMINOMA-TESTIS-1-1-1024x576.jpg&amp;f=1&amp;nofb=1&amp;ipt=80c565b8c2f4d42965432914e8c4631c97dd6d804b329cd9f3367d9c10778cea &quot;width=100%&quot;)\" id=\"note-1778953902191-4\">Семином</span></h3><p><strong>Класическият семином</strong> е най-чест около <strong>40-годишна възраст</strong> и не се развива преди 10-годишна възраст. Произхожда от герминативния епител на семенните каналчета и съставлява около <strong>50%</strong> от всички герминогенни тумори.</p><p>Макроскопски обикновено е <strong>едностранен</strong>, по-често в десния тестис. Тестисът е увеличен и съдържа възловидна туморна маса с мека до плътна консистенция. На срез туморът е солиден, <strong>бяло-сив</strong>, с добре очертани граници спрямо околната тъкан, но без капсула. Некрозите са редки, а кръвоизливите не са характерни.</p><p>Микроскопски класическият семином има <strong>гнезден строеж</strong>. Гнездата са изградени от големи, кръгли, еднообразни клетки със светла цитоплазма, богата на гликоген — <strong>PAS-позитивна</strong>. Ядрата са централни, големи, хиперхромни, с груб хроматин и едно до две базофилни ядърца. Не се образуват папили или тубули, което го отличава от ембрионалния карцином. Стромата е представена от съединителнотъканни септи с <strong>Т-лимфоцити</strong>, като по-изразеният лимфоцитарен инфилтрат се свързва с по-добра прогноза.</p><p>Туморните клетки инфилтрират интерстициума между семенните каналчета. Могат да се открият и каналчета с туморноклетъчни пролиферации тип <strong>carcinoma in situ</strong>. Митозите са редки. При <strong>3 или повече митози</strong> в едно зрително поле на голямо увеличение туморът се означава като <strong>анапластичен семином</strong>, при който има и по-изразен клетъчен полиморфизъм.</p><p>При клинично съмнение за семином се извършва <strong>орхидектомия без предварителна биопсия</strong>, за да се избегне дисеминация на тумора. Класическият семином е <strong>лъчечувствителен</strong>, а при напреднали случаи с множествени метастази се прилага химиотерапия.</p><h3>Сперматоцитен семином</h3><p><strong>Сперматоцитният семином</strong> се среща само в тестиса, обикновено при мъже над <strong>50 години</strong>. Докато класическият семином съставлява около <strong>90%</strong> от всички семиноми, сперматоцитният е около <strong>5%</strong>.</p><p>Макроскопски туморната маса може да достигне до <strong>15 cm</strong>, като границата е неясна. </p><p>Микроскопски се характеризира с по-изразен клетъчен полиморфизъм и съдържа три клетъчни типа: интермедиерни клетки, наподобяващи тези при класически семином; дребни лимфоцитоподобни клетки; и едри клетки с груб ядрен хроматин.</p><p>За разлика от класическия семином, цитоплазмата е <strong>PAS-отрицателна</strong>. Митозите са по-чести, но туморът обикновено <strong>не метастазира</strong> или метастазира много рядко.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Fwww.bosnianpathology.org%2Fwp-content%2Fuploads%2F2017%2F05%2FIMG_0539.JPG&amp;f=1&amp;nofb=1&amp;ipt=5c903359321a7d22e4e6d34c8a32f806346eeb74045f1a4dd1d01b24ccc944c6 &quot;width=100%&quot;)\" id=\"note-1778954009020-5\">Ембрионален карцином</span></h3><p><strong>Ембрионалният карцином</strong> се среща в около <strong>20–40%</strong> от всички герминативноклетъчни тумори на тестиса. Най-често дебютира във второто и третото десетилетие и рядко се среща при деца под 15 години.</p><p>Макроскопски се установява неясно ограничена туморна маса. Срезната повърхност е бледосива, често пъстра поради огнищни <strong>некрози</strong> и <strong>кръвоизливи</strong>.</p><p>Микроскопски туморът е изграден от примитивни епителни клетки със светла цитоплазма, които пролиферират под формата на <strong>ацини</strong>, <strong>тубули</strong> или солидни полета. Тубулите го отличават от класическия семином. Туморните клетки са едри, с неясни контури и висок малигнен потенциал. Могат да се открият гигантски многоядрени клетки тип <strong>синцитиотрофобласти</strong>, позитивни за <strong>ЧХГ</strong>, както и участъци, наподобяващи тумор на жълтъчната торбичка. За разлика от семинома, липсва изразена стромна реакция.</p><p>Метастазира както <strong>лимфогенно</strong>, така и <strong>хематогенно</strong> — в парааортални лимфни възли, бели дробове и черен дроб.</p><h3>Тератом</h3><p><strong>Тестикуларният тератом</strong> е чест в ранната детска възраст. </p><p>Макроскопски представлява мултикистична и солидна неоплазма, разрастваща се като възел в тестиса. Кистите могат да съдържат муцинозна материя, а в тумора се откриват участъци с хрущялна или костна тъкан. Обширни кръвоизливи не са типични.</p><p>Микроскопски тератомът е герминативноклетъчен тумор, съставен от тъкани или органоидни структури, произхождащи от трите зародишеви листа — <strong>ектодерма</strong>, <strong>мезодерма</strong> и <strong>ендодерма</strong>.</p><p>Според СЗО се различават:</p><ul><li><strong>зрял тератом</strong> — съставен от високодиференцирани тъкани с органоидна структура, без митози;</li><li><strong>незрял тератом</strong> — съдържа нискодиференцирани тъкани със склонност към органоидна диференциация и типични митози;</li><li><strong>тератом със злокачествена трансформация</strong> — отделни компоненти претърпяват малигнена трансформация, например в аденокарцином, плоскоклетъчен карцином, миосарком или хондросарком.</li></ul><p>Прогнозата при деца е по-добра, докато при възрастни зрелият тератом е непредсказуем. Тестикуларните тератоми могат да дават масивни метастази в костен мозък, бели дробове и черен дроб. Те са значително по-слабо лъчечувствителни от семиномите.</p><h3><span class=\"editor-note\" data-note=\"![Image](https://external-content.duckduckgo.com/iu/?u=https%3A%2F%2Filovepathology.com%2Fwp-content%2Fuploads%2F2024%2F12%2F13-1024x576.webp&amp;f=1&amp;nofb=1&amp;ipt=399e5d31c92c1ed846d0af3727e78618b6e74f527e592a794449826efe40c4e6 &quot;width=100%&quot;)\" id=\"note-1778954198384-6\">Хориокарцином</span></h3><p><strong>Хориокарциномът</strong> е крайно злокачествен герминативноклетъчен тумор с диференциация към екстраембрионални структури. В чист вид е рядък — около <strong>1%</strong> от всички герминативноклетъчни неоплазми. По-често се среща като компонент на смесени герминативни тумори, заедно с участъци от тератом, семином или ембрионален карцином.</p><p>Най-често се открива между <strong>20–30-годишна възраст</strong>. В серума и урината нивото на <strong>човешкия хорионгонадотропин — ЧХГ</strong> е трайно повишено, което е патогномоничен маркер.</p><p>Макроскопски представлява малък, слабо болезнен възел на тестиса. Консистенцията му зависи от големината на кръвоизливите, които са характерни за този тумор.</p><p>Микроскопски се наблюдават два вида клетки: <strong>синцитиотрофобластни клетки</strong> — многоядрени, гигантски, уродливи, с хиперхромни ядра и еозинофилна, често вакуолизирана цитоплазма; и <strong>цитотрофобластни клетки</strong> — със светла цитоплазма, умерено уголемени мехурести ядра и добре очертани клетъчни мембрани. Съчетанието на тези клетки с обширни <strong>кръвоизливи</strong> и <strong>некрози</strong> е типично за хориокарцинома. Туморът няма съединителнотъканна строма.</p><p>Разпространява се главно <strong>хематогенно</strong> — към черен дроб, бял дроб и мозък. Лимфогенното метастазиране е по-рядко. Хориокарциномите не са лъчечувствителни, но химиотерапията може да има сравнително добър ефект.</p><hr contenteditable=\"false\" data-editor-void=\"true\" tabindex=\"-1\"><h2>Тумори на епидидима</h2><h3>Аденоматоиден тумор</h3><p><strong>Аденоматоидният тумор</strong> — <strong>tumor adenomatoides</strong> — е доброкачествен тумор на епидидима. Среща се и със синонима <strong>mesothelioma benigna</strong>.</p><p>В епидидима може да се развие т.нар. <strong>непапиларна форма на доброкачествения мезотелиом</strong>.</p><p><strong>Макроскопски</strong> се представя като малко възелче с размер от няколко милиметра до около <strong>2 cm</strong> в диаметър.</p><p><strong>Микроскопски</strong> се различават три форми:</p><ul><li><strong>мрежовидна</strong>;</li><li><strong>тубуларна</strong>;</li><li><strong>смесена</strong>.</li></ul><p>Туморите наподобяват съдови неоплазми, изградени от малки кистички или тубули, разположени сред светла фиброзна интерстициална тъкан. Стените на дребните кистозни образувания са тапицирани от <strong>кубичен до плосък епител</strong>.</p><p><strong>Папиларните кистаденоми</strong> и <strong>карциномите на епидидима</strong> са много редки неоплазми.</p><br><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p><p><br></p>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/katex.min.js\"></script>\n<script src=\"https://cdn.jsdelivr.net/npm/katex@0.16.4/dist/contrib/auto-render.min.js\"></script>\n<script>\nrenderMathInElement(document.body, {\n  delimiters: [\n    {left: '$$', right: '$$', display: true},\n    {left: '$', right: '$', display: false},\n    {left: '\\\\[', right: '\\\\]', display: true},\n    {left: '\\\\(', right: '\\\\)', display: false}\n  ],\n  throwOnError: false\n});\n</script>\n</body>\n</html>";
